import React, { useState, useEffect, useMemo } from 'react';
import Select from 'react-select';
import './EditPurchase.css';

const EditPurchase = ({ handleEdit, editingPurchase, locations, vendors }) => {
  // Check if the 'editingPurchase' prop is valid or null
  if (!editingPurchase) {
    return <div>No purchase data provided for editing.</div>;
  }

  useEffect(() => {
    fetchDataForEdit();
  }, [editingPurchase.materialid]);

  const initialPurchaseState = {
    location: editingPurchase.location,
    materialid: editingPurchase.materialid,
    materialname: editingPurchase.materialname,
    quantity: editingPurchase.quantity,
    price: editingPurchase.price,
    vendor: editingPurchase.vendor,
    vendorname: editingPurchase.vendorname,
    width: editingPurchase.width || null,
    lotnumber: editingPurchase.lotnumber || '',
    // Add other missing fields with their initial values
    // e.g., field: editingPurchase.field || initialValue,
  };
  console.log('initialPurchaseState:', initialPurchaseState);

  const [editedPurchase, setEditedPurchase] = useState(initialPurchaseState);
  const [showExtras, setShowExtras] = useState(false);

  const fetchDataForEdit = async () => {
    try {
      const [responseList] = await Promise.all([
        fetch(`http://localhost:8081/materiallist/${editedPurchase.materialid}`),
      ]);

      const [dataList] = await Promise.all([
        responseList.json(),
      ]);
      console.log('Data list fetched:', dataList);

        // Check if extras=1 in the materiallist data
      if (dataList && dataList.extras === 1) {
        console.log('Showing extras...');
        setShowExtras(true);
      } else {
        console.log('Hiding extras...');
        setShowExtras(false);
      };
    } catch (error) {
        console.error('Error fetching material data:', error);
      }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setEditedPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    // Convert the selected vendor name back to vendor ID before submitting to the API
    const selectedVendor = vendors.find((vendor) => vendor.name === editedPurchase.vendorname);
    const updatedPurchase = {
      ...editedPurchase,
      vendor: selectedVendor ? selectedVendor.vendorid : '',
    };

    try {
      // Check if the material ID exists in material_changes
      const responseChanges = await fetch(`http://localhost:8081/materialchangesAPI/${editedPurchase.materialid}`);
      const dataChanges = await responseChanges.json();
      console.log('Data changes fetched:', dataChanges);

      // Check if there are changes in price, vendor, or lotnumber
      const hasChanges =
        dataChanges &&
        (dataChanges.price !== editedPurchase.price ||
          dataChanges.vendor !== updatedPurchase.vendor ||
          dataChanges.lotnumber !== editedPurchase.lotnumber);

      // If material ID exists and there are changes, update the existing record
      if (dataChanges && hasChanges) {
        const response = await fetch(`http://localhost:8081/materialchangesAPI/${editedPurchase.materialid}`, {
          method: 'PUT',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            price: editedPurchase.price,
            vendor: updatedPurchase.vendor,
            width: editedPurchase.width,
            lotnumber: editedPurchase.lotnumber,
          }),
        });

        if (!response.ok) {
          console.error('Failed to update material change:', response);
          // You can add additional error handling here, such as showing a user-friendly message.
          return;
        }
      }
    } catch (error) {
      console.error('Error handling the form submission:', error);
      // You can add additional error handling here, such as showing a user-friendly message.
      return;
    }

    // Call the handleEdit function to update the state with the edited purchase data
    handleEdit(updatedPurchase);

    // Reset the form state after submitting
    setEditedPurchase(initialPurchaseState);
  };

  const handleVendorChange = (selectedOption) => {
    if (!selectedOption) {
      setEditedPurchase((prevPurchase) => ({
        ...prevPurchase,
        vendor: '',
        vendorname: '',
      }));
      return;
    }

    // Find the vendor with the given name in the vendors array
    const selectedVendor = vendors.find((vendor) => vendor.name === selectedOption?.label);
    setEditedPurchase((prevPurchase) => ({
      ...prevPurchase,
      vendor: selectedVendor ? selectedVendor.vendorid : '',
      vendorname: selectedOption ? selectedOption.label : '',
    }));
  };

  const vendorOptions = useMemo(
    () => vendors.map((vendor) => ({ value: vendor.name, label: vendor.name })),
    [vendors]
  );

  return (
    <form onSubmit={handleSubmit} className='add-purchase-form'>
      <div>
        <label>Location:</label>
        <select name="location" value={editingPurchase.location} onChange={handleChange} required>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>
      <div>
        <label>Material ID:</label>
        <input type="text" name="materialid" value={editingPurchase.materialid} onChange={handleChange} required />
      </div>
      <div>
        <label>Material Name:</label>
        <input type="text" name="materialname" value={editingPurchase.materialname} readOnly required />
      </div>
      {showExtras && (
        <div>
          <label>Width:</label>
          <input
            type="text"
            name="width"
            value={editingPurchase.width}
            onChange={handleChange}
            required
          />
        </div>
      )}
      {showExtras && (
        <div>
          <label>LOT#:</label>
          <input
            type="text"
            name="lotnumber"
            value={editingPurchase.lotnumber}
            onChange={handleChange}
            required
          />
        </div>
      )}
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={editingPurchase.quantity} onChange={handleChange} required />
      </div>
      <div>
        <label>Price:</label>
        <input type="text" name="price" value={editingPurchase.price} onChange={handleChange} required />
      </div>
      <div>
        <label>Vendor:</label>
        <Select
          options={vendorOptions}
          value={
            editingPurchase.vendorname
              ? { value: editingPurchase.vendorname, label: editingPurchase.vendorname }
              : null
          }
          onChange={handleVendorChange}
          placeholder="Select a Vendor"
          isSearchable
          required
        />
      </div>
      <button type="submit" className="add_purchase_btn">Add Purchase</button>
    </form>
  );
  
};


export default EditPurchase;
